import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { CashLedgerLine } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTabBar, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-thu-chi';
const PAGE_ID = 'baocao-thu-chi';
const TABS = [
  { id: 'ReceiptJournal', label: 'Thu' },
  { id: 'DisbursementJournal', label: 'Chi' },
  { id: 'CashBook', label: 'Sổ quỹ' },
];

const BaoCaoThuChiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const initial = monthStartEnd();
  const [fromDate, setFromDate] = useState(initial.fromDate);
  const [toDate, setToDate] = useState(initial.toDate);
  const [tab, setTab] = useState('ReceiptJournal');
  const [rows, setRows] = useState<CashLedgerLine[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getCashLedger({ fromDate, toDate, reportKind: tab, pageSize: 500 })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi tải báo cáo thu/chi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, tab, dispatch]);

  const totals = useMemo(() => {
    const receipts = rows.reduce((s, r) => s + (r.creditAmount ?? 0), 0);
    const payments = rows.reduce((s, r) => s + (r.debitAmount ?? 0), 0);
    return { receipts, payments };
  }, [rows]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
      />
    ),
    [fromDate, toDate, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo thu / chi"
      titleIconClass="fas fa-wallet"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/accounting/cash-ledger/export-excel"
      exportParams={{ fromDate, toDate, reportKind: tab }}
      exportFilename={`ThuChi-${tab}.xlsx`}
      tabBar={<ReportTabBar testId={TEST_ID} tabs={TABS} activeId={tab} onChange={setTab} />}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th className={reportStyles.colStt}>STT</th>
            <th>Ngày</th>
            <th>Số CT</th>
            <th>Diễn giải</th>
            <th className={reportStyles.colRight}>Thu</th>
            <th className={reportStyles.colRight}>Chi</th>
            <th className={reportStyles.colRight}>Số dư</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={`${r.voucherCode}-${i}`}>
              <td className={reportStyles.colStt}>{i + 1}</td>
              <td>{formatDate(r.entryDate)}</td>
              <td>{r.voucherCode}</td>
              <td>{r.description ?? '—'}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.creditAmount)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.debitAmount)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.runningBalance)}</td>
            </tr>
          ))}
          {rows.length > 0 && (
            <tr className={reportStyles.rowTotal}>
              <td colSpan={4}>Tổng cộng</td>
              <td className={reportStyles.colRight}>{formatVnd(totals.receipts)}</td>
              <td className={reportStyles.colRight}>{formatVnd(totals.payments)}</td>
              <td />
            </tr>
          )}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoThuChiPage;
